-- Idempotent local/demo menu enrichment.
-- Safe to run against an existing development database; seed.sql also
-- contains these rows for fresh resets.

on conflict (id) do update set name = excluded.name, sort_order = excluded.sort_order;

update categories set sort_order = case id
  when '11111111-1111-1111-1111-000000000003' then 60
  when '11111111-1111-1111-1111-000000000004' then 70
  else sort_order
end
where id in (
  '11111111-1111-1111-1111-000000000003',
  '11111111-1111-1111-1111-000000000004'
);

on conflict (id) do update set
  name = excluded.name,
  unit = excluded.unit,
  stock_qty = greatest(ingredients.stock_qty, excluded.stock_qty),
  low_stock_threshold = excluded.low_stock_threshold,
  auto_disable = excluded.auto_disable;

on conflict (id) do update set
  name = excluded.name,
  description = excluded.description,
  price = excluded.price,
  category_id = excluded.category_id,
  photo_url = excluded.photo_url,
  available = excluded.available,
  sort_order = excluded.sort_order;

update menu_items set photo_url = case id
  when '33333333-3333-3333-3333-000000000001' then 'https://images.unsplash.com/photo-1567188040759-fb8a883dc6d8?auto=format&fit=crop&w=900&q=80'
  when '33333333-3333-3333-3333-000000000002' then 'https://images.unsplash.com/photo-1626645738196-c2a7c87a8f58?auto=format&fit=crop&w=900&q=80'
  when '33333333-3333-3333-3333-000000000003' then 'https://images.unsplash.com/photo-1631452180519-c014fe946bc7?auto=format&fit=crop&w=900&q=80'
  when '33333333-3333-3333-3333-000000000004' then 'https://images.unsplash.com/photo-1603894584373-5ac82b2ae398?auto=format&fit=crop&w=900&q=80'
  when '33333333-3333-3333-3333-000000000005' then 'https://images.unsplash.com/photo-1589302168068-964664d93dc0?auto=format&fit=crop&w=900&q=80'
  when '33333333-3333-3333-3333-000000000006' then 'https://images.unsplash.com/photo-1627662239825-3e0ef1641886?auto=format&fit=crop&w=900&q=80'
  when '33333333-3333-3333-3333-000000000007' then 'https://images.unsplash.com/photo-1561336526-2914f13ceb36?auto=format&fit=crop&w=900&q=80'
  when '33333333-3333-3333-3333-000000000008' then 'https://images.unsplash.com/photo-1509042239860-f550ce710b93?auto=format&fit=crop&w=900&q=80'
  when '33333333-3333-3333-3333-000000000009' then 'https://images.unsplash.com/photo-1626201850123-4b2362b57427?auto=format&fit=crop&w=900&q=80'
  when '33333333-3333-3333-3333-00000000000a' then 'https://images.unsplash.com/photo-1605197161470-5d2a9af568af?auto=format&fit=crop&w=900&q=80'
  else photo_url
end
where photo_url is null
  and id between '33333333-3333-3333-3333-000000000001' and '33333333-3333-3333-3333-00000000000a';

on conflict (menu_item_id, ingredient_id) do update set qty_used = excluded.qty_used;

update menu_item_ingredients set customer_removable = true
where (menu_item_id, ingredient_id) in (
  ('33333333-3333-3333-3333-000000000001', '22222222-2222-2222-2222-000000000006'),
  ('33333333-3333-3333-3333-000000000003', '22222222-2222-2222-2222-000000000006'),
  ('33333333-3333-3333-3333-000000000004', '22222222-2222-2222-2222-000000000006'),
  ('33333333-3333-3333-3333-000000000005', '22222222-2222-2222-2222-000000000006'),
  ('33333333-3333-3333-3333-00000000000b', '22222222-2222-2222-2222-000000000012'),
  ('33333333-3333-3333-3333-00000000000b', '22222222-2222-2222-2222-000000000013'),
  ('33333333-3333-3333-3333-00000000000e', '22222222-2222-2222-2222-00000000000e'),
  ('33333333-3333-3333-3333-00000000000e', '22222222-2222-2222-2222-000000000012'),
  ('33333333-3333-3333-3333-00000000000e', '22222222-2222-2222-2222-000000000013'),
  ('33333333-3333-3333-3333-00000000000f', '22222222-2222-2222-2222-00000000000e'),
  ('33333333-3333-3333-3333-00000000000f', '22222222-2222-2222-2222-000000000012'),
  ('33333333-3333-3333-3333-000000000010', '22222222-2222-2222-2222-00000000000e'),
  ('33333333-3333-3333-3333-000000000010', '22222222-2222-2222-2222-000000000012'),
  ('33333333-3333-3333-3333-000000000012', '22222222-2222-2222-2222-00000000000e')
);

on conflict (id) do update set
  menu_item_id = excluded.menu_item_id,
  name = excluded.name,
  price = excluded.price,
  sort_order = excluded.sort_order,
  available = excluded.available;
